// The synthetic ensures has the shape
//
//     ({ &&& post1_self_.wf() && ... }) ==> det_pop_scheduler_for_idle_cpu_equal(...)
//
// At the *top* of the proof body, ONLY the original function's `requires`
// (the preconditions on `pre_self_` / `cpu_id`) are in the proof context.
// The big conjunction is the antecedent of the ensures-implication; it is
// NOT a free hypothesis.  That's why the previous attempt's first bare
// `assert(post1_self_.wf());` already failed.
//
// Repair: open an `if (full_antecedent) { ... }` block.  Inside that branch
// every antecedent conjunct is a free hypothesis, so we can (a) re-trigger
// the post1/post2 forall-quantifiers, (b) prove pointwise cross-side
// equalities for procs / containers / endpoints / threads, and (c) finish
// the domain / page_closure / scheduler-tail equalities via set & sequence
// extensionality.  By the WP rule for `if`, the assertions inside the
// branch are propagated as `antecedent ==> ...` facts to the
// ensures-verification step, which lines the post1/post2 triggers up for
// the determinism postcondition.

let owning = pre_self_.cpu_list@[cpu_id as int].owning_container;

if (post1_self_.wf())
    && (post1_self_.page_closure() =~= pre_self_.page_closure())
    && (post1_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post1_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post1_self_.thread_dom() == pre_self_.thread_dom())
    && (post1_self_.thread_dom().contains(r1))
    && (forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr)]
        post1_self_.proc_dom().contains(p_ptr) ==>
            post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr)]
        post1_self_.container_dom().contains(container_ptr) && container_ptr != owning ==>
            post1_self_.get_container(container_ptr)
                =~= pre_self_.get_container(container_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != r1 ==>
            pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) ==>
            pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    && (pre_self_.get_container(owning).quota
        == post1_self_.get_container(owning).quota)
    && (pre_self_.get_container(owning).owned_cpus
        == post1_self_.get_container(owning).owned_cpus)
    && (pre_self_.get_container(owning).owned_threads
        == post1_self_.get_container(owning).owned_threads)
    && (pre_self_.get_container(owning).scheduler@.skip(1)
        == post1_self_.get_container(owning).scheduler@)
    && (pre_self_.get_container(owning).owned_endpoints
        == post1_self_.get_container(owning).owned_endpoints)
    && (pre_self_.get_container(owning).children
        == post1_self_.get_container(owning).children)
    && (pre_self_.get_thread(r1).ipc_payload =~= post1_self_.get_thread(r1).ipc_payload)
    && (post1_self_.get_thread(r1).state =~= ThreadState::RUNNING)
    && (pre_self_.get_thread(r1).endpoint_descriptors
        =~= post1_self_.get_thread(r1).endpoint_descriptors)
    && (post2_self_.wf())
    && (post2_self_.page_closure() =~= pre_self_.page_closure())
    && (post2_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post2_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.thread_dom() == pre_self_.thread_dom())
    && (post2_self_.thread_dom().contains(r2))
    && (forall|p_ptr: ProcPtr|
        #![trigger post2_self_.get_proc(p_ptr)]
        post2_self_.proc_dom().contains(p_ptr) ==>
            post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post2_self_.get_container(container_ptr)]
        post2_self_.container_dom().contains(container_ptr) && container_ptr != owning ==>
            post2_self_.get_container(container_ptr)
                =~= pre_self_.get_container(container_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != r2 ==>
            pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post2_self_.get_endpoint(e_ptr)]
        pre_self_.endpoint_dom().contains(e_ptr) ==>
            pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    && (pre_self_.get_container(owning).quota
        == post2_self_.get_container(owning).quota)
    && (pre_self_.get_container(owning).owned_cpus
        == post2_self_.get_container(owning).owned_cpus)
    && (pre_self_.get_container(owning).owned_threads
        == post2_self_.get_container(owning).owned_threads)
    && (pre_self_.get_container(owning).scheduler@.skip(1)
        == post2_self_.get_container(owning).scheduler@)
    && (pre_self_.get_container(owning).owned_endpoints
        == post2_self_.get_container(owning).owned_endpoints)
    && (pre_self_.get_container(owning).children
        == post2_self_.get_container(owning).children)
    && (pre_self_.get_thread(r2).ipc_payload =~= post2_self_.get_thread(r2).ipc_payload)
    && (post2_self_.get_thread(r2).state =~= ThreadState::RUNNING)
    && (pre_self_.get_thread(r2).endpoint_descriptors
        =~= post2_self_.get_thread(r2).endpoint_descriptors)
{
    // ---- Inside the branch the full ensures-antecedent is a hypothesis. ----

    // (1) Domain equalities transit through `pre_self_` and lift via set
    //     extensionality.
    assert(post1_self_.container_dom() =~= post2_self_.container_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
    assert(post1_self_.endpoint_dom() =~= post2_self_.endpoint_dom());

    // (2) page_closure is pinned to pre_self_'s on both sides.
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());

    // (3) The owning container's `scheduler@` is forced equal because both
    //     sides equal `pre_self_.get_container(owning).scheduler@.skip(1)`.
    assert(post1_self_.get_container(owning).scheduler@
        =~= post2_self_.get_container(owning).scheduler@);

    // (4) Pointwise equality of `get_proc` across the two runs: both runs
    //     pin every proc to `pre_self_.get_proc(...)`.
    assert forall|p_ptr: ProcPtr| post1_self_.proc_dom().contains(p_ptr) implies
        #[trigger] post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.proc_dom().contains(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    };

    // (5) Pointwise equality of `get_container` away from `owning`.
    assert forall|c_ptr: ContainerPtr|
        post1_self_.container_dom().contains(c_ptr) && c_ptr != owning implies
        #[trigger] post1_self_.get_container(c_ptr)
            =~= post2_self_.get_container(c_ptr) by {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.container_dom().contains(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    };

    // (6) Pointwise equality of `get_endpoint` over the whole endpoint domain.
    assert forall|e_ptr: EndpointPtr| pre_self_.endpoint_dom().contains(e_ptr) implies
        #[trigger] post1_self_.get_endpoint(e_ptr)
            =~= post2_self_.get_endpoint(e_ptr) by {
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    };

    // (7) Pointwise equality of `get_thread` away from `r1` AND `r2`.
    assert forall|t_ptr: ThreadPtr|
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != r1 && t_ptr != r2 implies
        #[trigger] post1_self_.get_thread(t_ptr)
            =~= post2_self_.get_thread(t_ptr) by {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    };

    // (8) Owning-container field-by-field cross equalities (every one of
    //     these has the form `post1.get_container(owning).F == post2.get_container(owning).F`
    //     because both sides pin F to `pre_self_.get_container(owning).F`,
    //     except `scheduler@` which is pinned to `.skip(1)`).
    assert(post1_self_.get_container(owning).quota
        == post2_self_.get_container(owning).quota);
    assert(post1_self_.get_container(owning).owned_cpus
        == post2_self_.get_container(owning).owned_cpus);
    assert(post1_self_.get_container(owning).owned_threads
        == post2_self_.get_container(owning).owned_threads);
    assert(post1_self_.get_container(owning).owned_endpoints
        == post2_self_.get_container(owning).owned_endpoints);
    assert(post1_self_.get_container(owning).children
        == post2_self_.get_container(owning).children);

    // (9) Per-r1 / per-r2 thread field equalities the ensures gives us.
    assert(post1_self_.get_thread(r1).state =~= ThreadState::RUNNING);
    assert(post2_self_.get_thread(r2).state =~= ThreadState::RUNNING);
    assert(post1_self_.get_thread(r1).ipc_payload
        =~= pre_self_.get_thread(r1).ipc_payload);
    assert(post2_self_.get_thread(r2).ipc_payload
        =~= pre_self_.get_thread(r2).ipc_payload);
    assert(post1_self_.get_thread(r1).endpoint_descriptors
        =~= pre_self_.get_thread(r1).endpoint_descriptors);
    assert(post2_self_.get_thread(r2).endpoint_descriptors
        =~= pre_self_.get_thread(r2).endpoint_descriptors);
}
